import { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { FaArrowLeft, FaCalendarAlt, FaBuilding, FaUsers, FaChartLine, FaCheckCircle, FaDownload, FaShareAlt, FaBookmark, FaRegBookmark } from 'react-icons/fa';
import Spinner from '../components/Spinner';
import schemeService from '../api/schemeService';
import { useContext } from 'react';
import AuthContext from '../context/AuthContext';

function SchemeDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user, isAuthenticated } = useContext(AuthContext);
  
  const [scheme, setScheme] = useState(null);
  const [loading, setLoading] = useState(true);
  const [bookmarked, setBookmarked] = useState(false);
  const [applyModalOpen, setApplyModalOpen] = useState(false);
  const [applicationData, setApplicationData] = useState({
    name: user ? user.name : '',
    email: user ? user.email : '',
    phone: '',
    address: '',
    farmSize: '',
    comments: '',
  });

  useEffect(() => {
    const fetchScheme = async () => {
      try {
        const data = await schemeService.getSchemeById(id);
        setScheme(data);
        
        // Check if user has bookmarked this scheme
        if (isAuthenticated && user) {
          const userBookmarks = await schemeService.getUserBookmarks(user.token);
          setBookmarked(userBookmarks.some(bookmark => bookmark._id === id));
        }
      } catch (error) {
        console.error('Error fetching scheme:', error);
        toast.error('Failed to load scheme details');
        navigate('/schemes');
      } finally {
        setLoading(false);
      }
    };

    fetchScheme();
  }, [id, isAuthenticated, user, navigate]);

  const handleBookmark = async () => {
    if (!isAuthenticated) {
      toast.info('Please log in to bookmark schemes');
      navigate('/login');
      return;
    }

    try {
      if (bookmarked) {
        await schemeService.removeBookmark(id, user.token);
        toast.success('Bookmark removed');
      } else {
        await schemeService.addBookmark(id, user.token);
        toast.success('Scheme bookmarked');
      }
      setBookmarked(!bookmarked);
    } catch (error) {
      toast.error('Failed to update bookmark');
    }
  };

  const handleShare = () => {
    navigator.clipboard.writeText(window.location.href);
    toast.success('Link copied to clipboard');
  };

  const handleApplyModalOpen = () => {
    if (!isAuthenticated) {
      toast.info('Please log in to apply for schemes');
      navigate('/login');
      return;
    }
    setApplyModalOpen(true);
  };

  const handleApplyModalClose = () => {
    setApplyModalOpen(false);
  };

  const handleApplicationChange = (e) => {
    const { name, value } = e.target;
    setApplicationData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleApplicationSubmit = async (e) => {
    e.preventDefault();
    
    // Validate form
    if (!applicationData.name || !applicationData.email || !applicationData.phone) {
      toast.error('Please fill all required fields');
      return;
    }
    
    try {
      await schemeService.applyForScheme(id, applicationData, user.token);
      toast.success('Application submitted successfully');
      setApplyModalOpen(false);
    } catch (error) {
      toast.error('Failed to submit application');
    }
  };

  if (loading) {
    return <Spinner />;
  }

  if (!scheme) {
    return (
      <div className="text-center p-6">
        <h2 className="text-xl text-red-600">Scheme not found</h2>
        <Link to="/schemes" className="btn btn-primary mt-4">
          <FaArrowLeft className="mr-2" /> Back to Schemes
        </Link>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-6">
      <div className="mb-6">
        <Link to="/schemes" className="text-green-600 hover:text-green-700 flex items-center">
          <FaArrowLeft className="mr-2" /> Back to Schemes
        </Link>
      </div>

      <div className="bg-white rounded-lg shadow-md overflow-hidden">
        {/* Header Section */}
        <div className="bg-green-600 p-6 text-white">
          <div className="flex justify-between items-start">
            <h1 className="text-2xl md:text-3xl font-bold">{scheme.name}</h1>
            <div className="flex space-x-3">
              <button 
                onClick={handleBookmark} 
                className="text-white hover:text-yellow-300"
                title={bookmarked ? 'Remove bookmark' : 'Bookmark this scheme'}
              >
                {bookmarked ? <FaBookmark size={20} /> : <FaRegBookmark size={20} />}
              </button>
              <button 
                onClick={handleShare} 
                className="text-white hover:text-yellow-300"
                title="Share this scheme"
              >
                <FaShareAlt size={20} />
              </button>
            </div>
          </div>
          <div className="mt-2 flex flex-wrap gap-3">
            <span className="inline-flex items-center bg-green-700 px-3 py-1 rounded-full text-sm">
              <FaBuilding className="mr-1" /> {scheme.department}
            </span>
            <span className="inline-flex items-center bg-green-700 px-3 py-1 rounded-full text-sm">
              <FaCalendarAlt className="mr-1" /> {new Date(scheme.lastDate).toLocaleDateString()}
            </span>
          </div>
        </div>

        {/* Content Section */}
        <div className="p-6">
          {/* Description */}
          <div className="mb-6">
            <h2 className="text-xl font-semibold text-gray-800 mb-3">Description</h2>
            <p className="text-gray-700">{scheme.description}</p>
          </div>

          {/* Details Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
            {/* Eligibility */}
            <div className="bg-gray-50 p-4 rounded-lg">
              <h3 className="text-lg font-semibold text-gray-800 mb-3 flex items-center">
                <FaUsers className="mr-2 text-green-600" /> Eligibility
              </h3>
              <p className="text-gray-700">{scheme.eligibility}</p>
            </div>

            {/* Benefits */}
            <div className="bg-gray-50 p-4 rounded-lg">
              <h3 className="text-lg font-semibold text-gray-800 mb-3 flex items-center">
                <FaChartLine className="mr-2 text-green-600" /> Benefits
              </h3>
              <p className="text-gray-700">{scheme.benefits}</p>
            </div>
          </div>

          {/* Process */}
          <div className="mb-6">
            <h2 className="text-xl font-semibold text-gray-800 mb-3">Application Process</h2>
            <div className="bg-gray-50 p-4 rounded-lg">
              <ol className="list-decimal pl-5 space-y-2">
                {scheme.process && scheme.process.split('\n').map((step, index) => (
                  <li key={index} className="text-gray-700">{step}</li>
                ))}
                {!scheme.process && <li className="text-gray-700">Contact the department for application process details.</li>}
              </ol>
            </div>
          </div>

          {/* Documents Required */}
          {scheme.documents && (
            <div className="mb-6">
              <h2 className="text-xl font-semibold text-gray-800 mb-3">Required Documents</h2>
              <div className="bg-gray-50 p-4 rounded-lg">
                <ul className="list-disc pl-5 space-y-2">
                  {scheme.documents.split('\n').map((doc, index) => (
                    <li key={index} className="text-gray-700 flex items-start">
                      <FaCheckCircle className="text-green-500 mt-1 mr-2 flex-shrink-0" />
                      <span>{doc}</span>
                    </li>
                  ))}
                </ul>
              </div>
            </div>
          )}

          {/* Additional Information */}
          {scheme.additionalInfo && (
            <div className="mb-6">
              <h2 className="text-xl font-semibold text-gray-800 mb-3">Additional Information</h2>
              <p className="text-gray-700">{scheme.additionalInfo}</p>
            </div>
          )}

          {/* Contact Information */}
          <div className="mb-6">
            <h2 className="text-xl font-semibold text-gray-800 mb-3">Contact Information</h2>
            <div className="bg-gray-50 p-4 rounded-lg">
              <p className="text-gray-700">
                <strong>Department:</strong> {scheme.department}<br />
                {scheme.contactInfo && <><strong>Contact:</strong> {scheme.contactInfo}<br /></>}
                <strong>Website:</strong>{' '}
                {scheme.websiteUrl ? (
                  <a 
                    href={scheme.websiteUrl} 
                    target="_blank" 
                    rel="noopener noreferrer" 
                    className="text-blue-600 hover:underline"
                  >
                    {scheme.websiteUrl}
                  </a>
                ) : (
                  'Not available'
                )}
              </p>
            </div>
          </div>

          {/* Action Buttons */}
          <div className="flex flex-wrap gap-4 mt-8">
            <button
              onClick={handleApplyModalOpen}
              className="btn btn-primary flex items-center"
            >
              Apply Now
            </button>
            
            {scheme.formUrl && (
              <a
                href={scheme.formUrl}
                target="_blank"
                rel="noopener noreferrer"
                className="btn btn-secondary flex items-center"
              >
                <FaDownload className="mr-2" /> Download Form
              </a>
            )}
          </div>
        </div>
      </div>

      {/* Application Modal */}
      {applyModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-lg max-w-2xl w-full max-h-90vh overflow-y-auto">
            <div className="p-6">
              <div className="flex justify-between items-center mb-4">
                <h2 className="text-xl font-bold text-gray-800">Apply for {scheme.name}</h2>
                <button 
                  onClick={handleApplyModalClose}
                  className="text-gray-500 hover:text-gray-700"
                >
                  &times;
                </button>
              </div>

              <form onSubmit={handleApplicationSubmit}>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                  <div className="form-group">
                    <label htmlFor="name" className="block text-gray-700 mb-1">Full Name *</label>
                    <input
                      type="text"
                      id="name"
                      name="name"
                      value={applicationData.name}
                      onChange={handleApplicationChange}
                      className="form-control"
                      required
                    />
                  </div>
                  
                  <div className="form-group">
                    <label htmlFor="email" className="block text-gray-700 mb-1">Email *</label>
                    <input
                      type="email"
                      id="email"
                      name="email"
                      value={applicationData.email}
                      onChange={handleApplicationChange}
                      className="form-control"
                      required
                    />
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                  <div className="form-group">
                    <label htmlFor="phone" className="block text-gray-700 mb-1">Phone Number *</label>
                    <input
                      type="tel"
                      id="phone"
                      name="phone"
                      value={applicationData.phone}
                      onChange={handleApplicationChange}
                      className="form-control"
                      required
                    />
                  </div>
                  
                  <div className="form-group">
                    <label htmlFor="farmSize" className="block text-gray-700 mb-1">Farm Size (in acres)</label>
                    <input
                      type="text"
                      id="farmSize"
                      name="farmSize"
                      value={applicationData.farmSize}
                      onChange={handleApplicationChange}
                      className="form-control"
                    />
                  </div>
                </div>

                <div className="form-group mb-4">
                  <label htmlFor="address" className="block text-gray-700 mb-1">Address</label>
                  <textarea
                    id="address"
                    name="address"
                    value={applicationData.address}
                    onChange={handleApplicationChange}
                    className="form-control"
                    rows="2"
                  ></textarea>
                </div>

                <div className="form-group mb-6">
                  <label htmlFor="comments" className="block text-gray-700 mb-1">Additional Comments</label>
                  <textarea
                    id="comments"
                    name="comments"
                    value={applicationData.comments}
                    onChange={handleApplicationChange}
                    className="form-control"
                    rows="3"
                    placeholder="Any specific details about your situation or questions about the scheme"
                  ></textarea>
                </div>

                <div className="flex gap-3 justify-end">
                  <button
                    type="button"
                    onClick={handleApplyModalClose}
                    className="btn btn-secondary"
                  >
                    Cancel
                  </button>
                  <button
                    type="submit"
                    className="btn btn-primary"
                  >
                    Submit Application
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default SchemeDetail;
